    const resetReconciliation = useCallback(async () => {
        setMatchResults([]);
        setReportPreviewData(null);
        setActiveReportId(null);
        setHasActiveSession(false);
        setBankStatementFile([]);
        setContributorFiles([]);
        setSelectedBankIds([]);
        await clearRemoteList();
        showToast("Sistema resetado.", "success");
        setActiveView('upload');
    }, [clearRemoteList, showToast, setActiveView]);

    const handleAnalyze = useCallback(async (tx: Transaction, contributors: Contributor[]) => {
        setUiFeedback(prev => ({ ...prev, loadingAiId: tx.id }));
        try {
            const name = await getAISuggestion(tx, contributors);
            setUiFeedback(prev => ({ ...prev, aiSuggestion: { id: tx.id, name }, loadingAiId: null }));
        } catch (e) {
            setUiFeedback(prev => ({ ...prev, loadingAiId: null }));
        }
    }, []);

    return {
        activeBankFiles, contributorFiles, matchResults, reportPreviewData,
        activeReportId, setActiveReportId, hasActiveSession, setHasActiveSession,
        comparisonType, setComparisonType, selectedBankIds,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        importGmailTransactions,
        ...uiFeedback,
        setUiFeedback,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile,
        removeContributorFile, toggleBankSelection, handleCompare, resetReconciliation,
        revertMatch, updateReportData, handleAnalyze, setMatchResults, setReportPreviewData,
        setBankStatementFile,
        closeManualIdentify: () => {
            setManualIdentificationTx(null);
            setBulkIdentificationTxs([]);
        },
        findMatchResult: (id: string) => matchResults.find(r => r.transaction.id === id),
        removeTransaction: (id: string) => {
            setMatchResults(prev => {
                const next = prev.filter(r => r.transaction.id !== id);
                regenerateReportPreview(next);
                return next;
            });
        }
    };
};

import { useEffect, useCallback, useRef } from 'react';
import { Transaction } from '../types';
import { consolidationService } from '../services/ConsolidationService';

interface UseLiveListSyncProps {
    user: any;
    setBankStatementFile: (fn: (prev: any[]) => any[]) => void;
    setSelectedBankIds: (fn: (prev: string[]) => string[]) => void;
    showToast?: (msg: string, type: 'success' | 'error') => void;
}

export const useLiveListSync = ({
    user,
    setBankStatementFile,
    setSelectedBankIds,
    showToast
}: UseLiveListSyncProps) => {
    // Trava de segurança para impedir múltiplas execuções simultâneas
    const isHydrating = useRef(false);
    const hasHydrated = useRef(false);
    const lastUserId = useRef<string | null>(null);

    // --- HIDRATAÇÃO: Recupera do DB ao iniciar ---
    useEffect(() => {
        // Só executa se tiver usuário, não estiver hidratando e o usuário mudou ou nunca hidratou
        if (!user || isHydrating.current || (hasHydrated.current && lastUserId.current === user.id)) return;

        const hydrate = async () => {
            isHydrating.current = true;
            lastUserId.current = user.id;

            try {
                console.log(`[Lista Viva] Iniciando recuperação de dados para usuário: ${user.id}`);

                // Busca as transações com limite de segurança para evitar Erro 400/Timeout
                const dbTransactions = await consolidationService.getPendingTransactions(user.id);

                if (!dbTransactions || dbTransactions.length === 0) {
                    hasHydrated.current = true;
                    isHydrating.current = false;
                    return;
                }

                const groupedByBank: Record<string, Transaction[]> = {};

                // Processamento otimizado: Limita a 2000 registros para garantir estabilidade da UI
                const safeTransactions = dbTransactions.slice(0, 2000);

                safeTransactions.forEach((t: any) => {
                    const bankId = t.bank_id || 'unknown';
                    const tx: Transaction = {
                        id: t.id,
                        date: t.transaction_date,
                        description: t.description,
                        rawDescription: t.description,
                        amount: t.amount,
                        originalAmount: String(t.amount.toFixed(2)),
                        contributionType: t.type === 'income' ? 'ENTRADA' : 'SAÍDA',
                        cleanedDescription: t.description
                    };
                    if (!groupedByBank[bankId]) groupedByBank[bankId] = [];
                    groupedByBank[bankId].push(tx);
                });

                const restoredFiles = Object.entries(groupedByBank).map(([bankId, txs]) => ({
                    bankId,
                    content: '',
                    fileName: `Lista Viva (Recuperada)`,
                    rawFile: undefined,
                    processedTransactions: txs,
                    isRestored: true
                }));

                // Atualização atômica do estado para evitar múltiplos disparos de render
                setBankStatementFile(() => restoredFiles);
                setSelectedBankIds(() => restoredFiles.map(f => f.bankId));

                hasHydrated.current = true;
                console.log(`[Lista Viva] ${safeTransactions.length} transações restauradas com sucesso.`);
            } catch (err) {
                console.error("[Lista Viva] Erro crítico na hidratação:", err);
            } finally {
                isHydrating.current = false;
            }
        };

        hydrate();
    }, [user, setBankStatementFile, setSelectedBankIds]);

    /**
     * 🛡️ PERSISTÊNCIA BLINDADA COM DEDUPLICAÇÃO POR CONTEÚDO (V12)
     * Garante que apenas linhas inéditas (Data|Descrição|Valor) entrem no Banco/Lista Viva.
     */
    const persistTransactions = useCallback(async (bankId: string, transactions: Transaction[]) => {
        if (!user || transactions.length === 0) return;

        console.log("[ListaViva:PERSIST_START]");

        try {
            // 1. CONSTRUIR ÍNDICE DOS EXISTENTES (Recuperação atual do Banco)
            const currentTxs = await consolidationService.getPendingTransactions(user.id);
            const existingKeys = new Set(currentTxs.map((t: any) => 
                `${t.transaction_date}|${t.description}|${Number(t.amount).toFixed(2)}`
            ));

            // 2. FILTRAR ANTES DE SALVAR (Chave Lógica)
            const filteredNewTransactions = transactions.filter(t => {
                const key = `${t.date}|${t.description}|${Number(t.amount).toFixed(2)}`;
                if (existingKeys.has(key)) {
                    console.log(`[ListaViva:DUPLICATE_BLOCKED] Ignorando linha idêntica: ${key}`);
                    return false;
                }
                return true;
            });

            if (filteredNewTransactions.length === 0) {
                console.log("[ListaViva:PERSIST_END] Nenhuma linha nova para persistir.");
                return;
            }

            // 3. PERSISTÊNCIA REAL (Apenas registros inéditos)
            const chunkSize = 100;
            for (let i = 0; i < filteredNewTransactions.length; i += chunkSize) {
                const chunk = filteredNewTransactions.slice(i, i + chunkSize);
                const data = chunk.map(t => ({
                    transaction_date: t.date,
                    amount: t.amount,
                    description: t.description,
                    type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                    pix_key: null,
                    source: 'file' as 'file',
                    user_id: user.id,
                    bank_id: bankId.length > 10 ? bankId : null 
                }));
                await consolidationService.addTransactions(data);
            }

            console.log(`[ListaViva:PERSIST_END] ${filteredNewTransactions.length} novas linhas persistidas.`);
        } catch (e) {
            console.warn("[ListaViva:PERSIST_ERROR] Falha na sincronização remota", e);
        }
    }, [user]);

    const clearRemoteList = useCallback(async (bankId?: string) => {
        if (!user) return;
        try {
            await consolidationService.deletePendingTransactions(user.id, bankId);
            // Resetamos a flag para permitir nova hidratação se necessário
            hasHydrated.current = false;
        } catch (e) {
            console.error("[Lista Viva] Erro ao limpar banco remoto:", e);
        }
    }, [user]);

    return { persistTransactions, clearRemoteList };
};
